import '../lib/cache.dart';

void main() {
  var now = DateTime.utc(2099, 1, 1);
  final cache = TtlCache<String>(() => now);
  cache.put('alpha', 'one', const Duration(seconds: 10));
  if (cache.get('alpha') != 'one') {
    throw StateError('fresh value should be returned');
  }
  print('public cache contract passed');
}
